import {
  Box,
  Button,
  Flex,
  Grid,
  Image,
  Text,
  Textarea,
} from "@chakra-ui/react";
import React, { useState } from "react";
import AdminNavTop from "../AdminNavTop";

const data = [
  {
    image:
      "https://images.unsplash.com/photo-1607082349566-187342175e2f?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxzZWFyY2h8M3x8ZGlzY291bnR8ZW58MHx8MHx8fDA%3D&w=1000&q=80",
    desc: "50% Discount available",
  },
  {
    image:
      "https://images.unsplash.com/photo-1607082349566-187342175e2f?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxzZWFyY2h8M3x8ZGlzY291bnR8ZW58MHx8MHx8fDA%3D&w=1000&q=80",
    desc: "50% Discount available",
  },
  {
    image:
      "https://images.unsplash.com/photo-1607082349566-187342175e2f?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxzZWFyY2h8M3x8ZGlzY291bnR8ZW58MHx8MHx8fDA%3D&w=1000&q=80",
    desc: "50% Discount available",
  },
  {
    image:
      "https://images.unsplash.com/photo-1607082349566-187342175e2f?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxzZWFyY2h8M3x8ZGlzY291bnR8ZW58MHx8MHx8fDA%3D&w=1000&q=80",
    desc: "50% Discount available",
  },
  {
    image:
      "https://images.unsplash.com/photo-1607082349566-187342175e2f?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxzZWFyY2h8M3x8ZGlzY291bnR8ZW58MHx8MHx8fDA%3D&w=1000&q=80",
    desc: "50% Discount available",
  },
  {
    image:
      "https://images.unsplash.com/photo-1607082349566-187342175e2f?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxzZWFyY2h8M3x8ZGlzY291bnR8ZW58MHx8MHx8fDA%3D&w=1000&q=80",
    desc: "50% Discount available",
  },
  {
    image:
      "https://images.unsplash.com/photo-1607082349566-187342175e2f?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxzZWFyY2h8M3x8ZGlzY291bnR8ZW58MHx8MHx8fDA%3D&w=1000&q=80",
    desc: "50% Discount available",
  },
  {
    image:
      "https://images.unsplash.com/photo-1607082349566-187342175e2f?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxzZWFyY2h8M3x8ZGlzY291bnR8ZW58MHx8MHx8fDA%3D&w=1000&q=80",
    desc: "50% Discount available",
  },
  {
    image:
      "https://images.unsplash.com/photo-1607082349566-187342175e2f?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxzZWFyY2h8M3x8ZGlzY291bnR8ZW58MHx8MHx8fDA%3D&w=1000&q=80",
    desc: "50% Discount available",
  },
  {
    image:
      "https://images.unsplash.com/photo-1607082349566-187342175e2f?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxzZWFyY2h8M3x8ZGlzY291bnR8ZW58MHx8MHx8fDA%3D&w=1000&q=80",
    desc: "50% Discount available",
  },
];

const Discount = () => {
  const [discount, setDiscount] = useState(data);
  return (
  <Box bg="#f7f9fa" minH="100vh" p={6}>
    <AdminNavTop />

    <Box mt="80px">
      <Text fontSize="2xl" fontWeight="bold" mb={6}>
        Discount Campaigns
      </Text>

      <Grid
        templateColumns={{
          base: "1fr",
          md: "repeat(2,1fr)",
          lg: "repeat(3,1fr)",
        }}
        gap={6}
      >
        {discount.map((el, i) => (
          <Box
            key={i}
            bg="white"
            borderRadius="lg"
            overflow="hidden"
            boxShadow="lg"
            _hover={{
              transform: "translateY(-5px)",
              transition: "0.2s",
            }}
          >
            {/* IMAGE */}
            <Box position="relative">
              <Image
                src={el.image}
                w="100%"
                h="180px"
                objectFit="cover"
              />

              {/* OVERLAY */}
              <Box
                position="absolute"
                bottom="0"
                w="100%"
                bg="rgba(0,0,0,0.6)"
                color="white"
                p={3}
              >
                <Text fontWeight="bold">{el.desc}</Text>
              </Box>
            </Box>

            {/* ACTION */}
            <Flex justify="space-between" p={4}>
              <Button
                size="sm"
                colorScheme="red"
                variant="outline"
              >
                Delete
              </Button>

              <Button
                size="sm"
                bg="#A435F0"
                color="white"
                _hover={{ bg: "#8710d8" }}
              >
                Enable
              </Button>
            </Flex>
          </Box>
        ))}
      </Grid>
    </Box>
  </Box>
);
};

export default Discount;
